// ChannelServiceMCPDefaultBasePath is the default HTTP path prefix for
// ChannelService MCP endpoints, derived from the protobuf package and service name.
const ChannelServiceMCPDefaultBasePath = "/freebusy/channel/v1/channelservice/mcp"

// ChannelServiceCompletionMap returns a map of "promptName:argName" → allowed
// values, built from enum_values declared in the proto MCP options.
func ChannelServiceCompletionMap() map[string][]string {
	m := map[string][]string{}
	return m
}

// ServeChannelServiceMCP creates an MCP server, registers the service tools, and
// starts serving using the configured transport (streamable-http, sse, or stdio).
// Uses the proto-derived BasePath. This is a blocking call.
func ServeChannelServiceMCP(ctx context.Context, srv ChannelServiceMCPServer, cfg *runtime.MCPServerConfig, opts ...runtime.Option) error {
	// Set the proto-derived path as the generated default
	cfg.GeneratedBasePath = ChannelServiceMCPDefaultBasePath

	// Wire completion handler for prompt arguments with enum_values.
	completionMap := ChannelServiceCompletionMap()
	if len(completionMap) > 0 {
		if cfg.ServerOptions == nil {
			cfg.ServerOptions = &mcp.ServerOptions{}
		}
		cfg.ServerOptions.CompletionHandler = runtime.CompletionHandlerFromEnums(completionMap)
	}

	return runtime.StartServer(ctx, cfg, func(s *mcp.Server) {
		RegisterChannelServiceMCPHandler(s, srv, opts...)
	})
}

